  static String failures(String projectName) => '''
// Generated by flutter_clean_arch_cli
// ─────────────────────────────────────────────────────────────
// Failures
// Represents domain-level failures returned from use cases.
// Used with Either<Failure, T> from dartz package.
// ─────────────────────────────────────────────────────────────

import 'package:equatable/equatable.dart';

/// Base class for all failures in the app.
abstract class Failure extends Equatable {
  final String message;
  const Failure({required this.message});

  @override
  List<Object> get props => [message];
}

/// Failure for server-side errors (4xx, 5xx responses).
class ServerFailure extends Failure {
  const ServerFailure({required super.message});
}

/// Failure when the device has no internet connection.
class NetworkFailure extends Failure {
  const NetworkFailure({required super.message});
}

/// Failure for local cache/storage errors.
class CacheFailure extends Failure {
  const CacheFailure({required super.message});
}

/// Failure for authentication errors (401, 403).
class AuthFailure extends Failure {
  const AuthFailure({required super.message});
}

/// Failure when a requested item is not found (404).
class NotFoundFailure extends Failure {
  const NotFoundFailure({required super.message});
}

// TODO: Add custom failures specific to your domain below
// Example:
// class ValidationFailure extends Failure {
//   const ValidationFailure({required super.message});
// }
''';

