// Generated by flutter_clean_arch_cli
// ─────────────────────────────────────────────────────────────
// AppUtils
// General utility functions used across the app.
// TODO: Add your own utility methods here.
// ─────────────────────────────────────────────────────────────

import 'package:flutter/material.dart';

class AppUtils {
  AppUtils._();

  /// Shows a SnackBar with a message.
  static void showSnackBar(BuildContext context, String message, {bool isError = false}) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        backgroundColor: isError ? Colors.red : Colors.green,
        behavior: SnackBarBehavior.floating,
        duration: const Duration(seconds: 3),
      ),
    );
  }

  /// Shows a loading dialog.
  static void showLoadingDialog(BuildContext context) {
    showDialog(
      context: context,
      barrierDismissible: false,
      builder: (_) => const Center(child: CircularProgressIndicator()),
    );
  }

  /// Dismisses an open dialog.
  static void dismissDialog(BuildContext context) {
    if (Navigator.of(context).canPop()) {
      Navigator.of(context).pop();
    }
  }

  /// Formats a DateTime to a readable string.
  /// TODO: Customize date format as needed
  static String formatDate(DateTime date) {
    return '\${date.day}/\${date.month}/\${date.year}';
  }

  /// Validates an email address format.
  static bool isValidEmail(String email) {
    return RegExp(r'^[\\w-.]+@([\\w-]+\\.)+[\\w-]{2,4}\$').hasMatch(email);
  }

  /// Checks if a string is null or empty.
  static bool isNullOrEmpty(String? value) {
    return value == null || value.trim().isEmpty;
  }

  // TODO: Add more utility methods specific to your app
}
''';

