// Generated by flutter_clean_arch_cli
// ─────────────────────────────────────────────────────────────
// NetworkInfo
// Checks whether the device has an active internet connection.
// Uses internet_connection_checker package.
// ─────────────────────────────────────────────────────────────

import 'package:internet_connection_checker/internet_connection_checker.dart';

/// Abstract contract for network info
abstract class NetworkInfo {
  Future<bool> get isConnected;
}

/// Implementation using internet_connection_checker
class NetworkInfoImpl implements NetworkInfo {
  final InternetConnectionChecker connectionChecker;

  NetworkInfoImpl(this.connectionChecker);

  @override
  Future<bool> get isConnected => connectionChecker.hasConnection;
}
